import cv2
import face_recognition
import numpy as np
from flask import Flask, jsonify, request

app = Flask(__name__)

employee_faces_encodings = []
employee_names = []

def train_model(employee_photos_path):
    for emp_photo in employee_photos_path:
        image = face_recognition.load_image_file(emp_photo)
        encoding = face_recognition.face_encodings(image)[0]
        employee_faces_encodings.append(encoding)
        employee_names.append(emp_photo.split('/')[-1].split('.')[0])

train_model(['/path_to_employee_photos/employee1.jpg', '/path_to_employee_photos/employee2.jpg'])

@app.route('/recognize_faces', methods=['POST'])
def recognize_faces():
    data = request.files['image']
    img = face_recognition.load_image_file(data)
    face_locations = face_recognition.face_locations(img)
    face_encodings = face_recognition.face_encodings(img, face_locations)

    results = []
    for face_encoding in face_encodings:
        face_distances = face_recognition.face_distance(employee_faces_encodings, face_encoding)
        probabilities = 1 - face_distances
        result = dict(zip(employee_names, probabilities))
        results.append(result)

    return jsonify(results)

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0')